[Form]
public class ETGProvisionalChargesTable extends FormRun
{
    SysLookupMultiSelectCtrl msCtrlPurch, msCtrlSales;
    container               selectedFieldsPurch, selectedFieldsSales;
}

/// <summary>
///
/// </summary>
public void init()
{
    super();

    element.chargesIdLookupPurch();
    element.chargesIdLookupSales();
}

public void chargesIdLookupPurch()
{
    container               selectedFields;
    Query		            query		        = new Query();
    QueryBuildDataSource    qbdsMarkupTable   = query.addDataSource(tablenum(MarkupTable));

    qbdsMarkupTable.fields().addField(fieldNum(MarkupTable, MarkupCode));
    qbdsMarkupTable.fields().addField(fieldNum(MarkupTable, Txt));
    qbdsMarkupTable.addRange(fieldnum(MarkupTable, ModuleType)).value(queryValue(MarkupModuleType::Vend));

    selectedFieldsPurch = [tableNum(MarkupTable), fieldNum(MarkupTable, MarkupCode)];

    msCtrlPurch = SysLookupMultiSelectCtrl::constructWithQuery(element, ChargeCodePurch, query, false, selectedFieldsPurch);
    msCtrlPurch.set(msCtrlPurch.getSelectedFieldValues());
}

public void chargesIdLookupSales()
{
    container               selectedFields;
    Query		            query		        = new Query();
    QueryBuildDataSource    qbdsMarkupTable   = query.addDataSource(tablenum(MarkupTable));

    qbdsMarkupTable.fields().addField(fieldNum(MarkupTable, MarkupCode));
    qbdsMarkupTable.fields().addField(fieldNum(MarkupTable, Txt));

    selectedFieldsSales = [tableNum(MarkupTable), fieldNum(MarkupTable, MarkupCode)];
    qbdsMarkupTable.addRange(fieldnum(MarkupTable, ModuleType)).value(queryValue(MarkupModuleType::Cust));

    msCtrlSales = SysLookupMultiSelectCtrl::constructWithQuery(element, ChargeCodeSales, query, false, selectedFieldsSales);
    msCtrlSales.set(msCtrlPurch.getSelectedFieldValues());
}

/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    ETGGlobal::lookupSubVerticalCharges(_formControl, _filterStr);
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean validate()
{
    boolean ret = true;

    // NS, DLT Shreelekha, 13/06/2025 - Sub Vertical lookup: Should display only Business Unit records that are not suspended.

    if (ETGACFParameters::find().EnableProvisionalCharges)
    {

        ret = super();
        DimensionAttribute       dimAttr;
        DimensionAttributeValue _dimAttrValue;
        str errorLabelId = '';
        SelectableDataArea    company;
        DimensionAttrValueLedgerOverride dimAttrValueLedgerOverride;

        ETGACFParameters acfParameters = ETGACFParameters::find();
        CompanyInfo   companyInfo = CompanyInfo::find();
        LedgerRecId ledgerRecId   = Ledger::primaryLedger(companyInfo.RecId);
        dimAttr = DimensionAttribute::findByName(acfParameters.SubVertical);
        _dimAttrValue = DimensionAttributeValue::findByDimensionAttributeAndValue(
                    dimAttr, ETGProvisionalChargesTable.SubVertical);

        dimAttrValueLedgerOverride = DimensionAttrValueLedgerOverride::findByDimensionAttrValueLedgerOverride(
       _dimAttrValue.RecId, ledgerRecId, true);

        if (_dimAttrValue.IsSuspended || (dimAttrValueLedgerOverride && dimAttrValueLedgerOverride.IsSuspended))
        {
            warning(strFmt("The selected dimension value '%1' is suspended and cannot be used.", _dimAttrValue.DisplayValue));
            ret = false;
        }

    }
    return ret;

}
// NE, DLT Shreelekha, 13/06/2025 - Sub Vertical lookup: Should display only Business Unit records that are not suspended.
